import { useLocation, useNavigate } from "react-router-dom";
import "../App.css";

function QuizResult() {
  const location = useLocation();
  const navigate = useNavigate();
  const result = location.state;

  if (!result) {
    return (
      <div className="page-container"><div className="result-box"><h2>No result found.</h2><button className="quiz-button" onClick={() => navigate("/quiz-bank")}>Go Back</button></div></div>
    );
  }

  const percentage = Math.round((result.score / result.total) * 100);
  let feedbackMessage = percentage >= 80 ? "Outstanding! Excellent work. 🏆" : percentage >= 50 ? "Good effort! Keep practicing. 👍" : "Don't give up! Review the material and try again. 📚";
  let barColor = percentage >= 80 ? "#16a34a" : percentage >= 50 ? "#ca8a04" : "#dc2626";

  return (
    <div className="page-container">
      <div className="result-box">
        <h1 style={{ color: "var(--primary-dark)", marginBottom: "8px" }}>Quiz Complete!</h1>
        <h2 style={{ fontWeight: "500", color: "var(--text-soft)" }}>{result.title}</h2>
        <h3 style={{ color: barColor, marginTop: "24px", fontSize: "20px" }}>{feedbackMessage}</h3>
        <p className="result-score" style={{ fontSize: "18px", marginTop: "10px" }}>You scored <strong>{result.score}</strong> out of <strong>{result.total}</strong></p>

        <div className="progress-bar-container">
          <div className="progress-bar-fill" style={{ width: `${percentage}%`, backgroundColor: barColor }}>
            <span className="progress-bar-text">{percentage}%</span>
          </div>
        </div>

        <div className="result-actions">
          <button className="quiz-button" onClick={() => navigate("/quiz-bank")}>Back to Quiz Bank</button>
        </div>
      </div>
    </div>
  );
}
export default QuizResult;
